let raw = $.steps.fetchQuote.output || '[]';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try {
  const data = JSON.parse(raw);
  const quote = Array.isArray(data) ? data[0] : data;
  return { text: quote.q || quote.text || 'No quote found', author: quote.a || quote.author || 'Unknown' };
} catch(e) {
  return { text: 'The best time to plant a tree was 20 years ago. The second best time is now.', author: 'Chinese Proverb' };
}

const q = $.steps.parseQuote.output;
const now = new Date().toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });

const blocks = [
  { type: 'header', text: { type: 'plain_text', text: ':sparkles: Daily Inspiration', emoji: true } },
  { type: 'section', text: { type: 'mrkdwn', text: '> _' + q.text + '_' } },
  { type: 'context', elements: [{ type: 'mrkdwn', text: ':writing_hand: *' + q.author + '* | ' + now }] },
  { type: 'divider' },
  { type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by ZenQuotes API + One CLI' }] }
];

const fallback = '"' + q.text + '" — ' + q.author;
return { blocks, fallback };
